class Solution:
    def minDays(self, n: int) -> int:
        if n <= 2:
            return n
        res = 1
        while n > 1:
            if n % 3 == 0:
                n //= 3
            elif n % 2 == 0:
                n //= 2
            else:
                n -= 1
            res += 1
        return res

